import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../App';

const Logo = () => (
  <svg width="26" height="26" viewBox="0 0 48 48" fill="none">
    <path d="M24 3L5 11.5V23C5 34.5 13.2 43.5 24 45.5C34.8 43.5 43 34.5 43 23V11.5L24 3Z"
          fill="#16a34a" opacity="0.15" stroke="#16a34a" strokeWidth="2"/>
    <rect x="21.5" y="13" width="5" height="22" rx="2.5" fill="#16a34a"/>
    <rect x="13" y="21.5" width="22" height="5" rx="2.5" fill="#16a34a"/>
  </svg>
);

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => { logout(); navigate('/'); setMenuOpen(false); };
  const isActive = p => location.pathname === p || location.pathname.startsWith(p + '/');
  const onAdmin = location.pathname.startsWith('/admin');

  // If user is admin AND currently on /admin, don't show redundant top nav items
  // Only show: MediHelp logo, and on non-admin pages: Dashboard link
  const navLinkStyle = (active) => ({
    color: active ? '#16a34a' : '#6b7280',
    fontWeight: active ? 600 : 500,
    fontSize: '0.9rem',
    padding: '0.4rem 0.75rem',
    borderRadius: 8,
    textDecoration: 'none',
    display: 'flex',
    alignItems: 'center',
    gap: 6,
    transition: 'color 0.15s',
  });

  return (
    <>
      <nav style={{
        background: 'rgba(255,255,255,0.97)',
        backdropFilter: 'blur(12px)',
        borderBottom: '1px solid #e5e7eb',
        position: 'sticky', top: 0, zIndex: 100,
        height: 60,
      }}>
        <div style={{
          maxWidth: 1100, margin: '0 auto',
          padding: '0 1.25rem', height: '100%',
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        }}>
          {/* Logo */}
          <Link to={user ? (user.role === 'ADMIN' && onAdmin ? '/admin' : '/dashboard') : '/'}
                style={{ display:'flex', alignItems:'center', gap:8, textDecoration:'none' }}>
            <Logo/>
            <span style={{ fontFamily:'Fraunces, serif', fontWeight:700, fontSize:'1.15rem', color:'#111827' }}>
              MediHelp
            </span>
          </Link>

          {/* Desktop nav */}
          <div style={{ display:'flex', alignItems:'center', gap:6 }} className="desktop-nav">
            {!user ? (
              <>
                <Link to="/" style={navLinkStyle(location.pathname === '/')}>Home</Link>
                <Link to="/login" className="btn btn-outline btn-sm">Sign In</Link>
                <Link to="/register" className="btn btn-primary btn-sm">Get Started</Link>
              </>
            ) : onAdmin ? (
              // On admin page: only show "Back to Dashboard" — no duplicate Admin link
              <Link to="/dashboard" style={navLinkStyle(false)}>
                <i className="fa-solid fa-arrow-left" style={{fontSize:'0.8rem'}}/> Dashboard
              </Link>
            ) : (
              // Normal user nav
              <>
                <Link to="/dashboard" style={navLinkStyle(isActive('/dashboard'))}>Dashboard</Link>
                {user.role === 'ADMIN' && (
                  <Link to="/admin" style={navLinkStyle(isActive('/admin'))}>
                    <i className="fa-solid fa-gear" style={{fontSize:'0.75rem'}}/>Admin
                  </Link>
                )}
              </>
            )}
            {user && (
              <div style={{ display:'flex', alignItems:'center', gap:8, marginLeft:8, paddingLeft:8, borderLeft:'1px solid #e5e7eb' }}>
                <div style={{ width:30, height:30, borderRadius:'50%', background:'linear-gradient(135deg,#16a34a,#15803d)', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontSize:'0.8rem', fontWeight:700, flexShrink:0 }}>
                  {(user.name||'U')[0].toUpperCase()}
                </div>
                <span style={{ fontSize:'0.82rem', color:'#374151', fontWeight:500 }} className="hide-xs">
                  {user.name?.split(' ')[0]}
                </span>
                <button onClick={handleLogout} className="btn btn-ghost btn-sm">
                  <i className="fa-solid fa-right-from-bracket"/>
                </button>
              </div>
            )}
          </div>

          {/* Mobile hamburger */}
          <button onClick={()=>setMenuOpen(!menuOpen)} className="mobile-menu-btn" style={{
            display:'none', background:'none', border:'none', cursor:'pointer',
            color:'#374151', fontSize:'1.2rem', padding:6, borderRadius:6,
          }}>
            <i className={`fa-solid ${menuOpen ? 'fa-xmark' : 'fa-bars'}`}/>
          </button>
        </div>
      </nav>

      {/* Mobile dropdown */}
      {menuOpen && (
        <div style={{
          position:'fixed', top:60, left:0, right:0, background:'white',
          borderBottom:'1px solid #e5e7eb', zIndex:99,
          boxShadow:'0 8px 24px rgba(0,0,0,0.1)',
          padding:'0.75rem 1.25rem', display:'flex', flexDirection:'column', gap:4,
        }} className="mobile-menu">
          {!user ? (
            <>
              <Link to="/" onClick={()=>setMenuOpen(false)} style={navLinkStyle(location.pathname==='/')}>
                <i className="fa-solid fa-house"/>Home
              </Link>
              <Link to="/login" onClick={()=>setMenuOpen(false)} style={navLinkStyle(false)}>
                <i className="fa-solid fa-right-to-bracket"/>Sign In
              </Link>
              <Link to="/register" onClick={()=>setMenuOpen(false)} style={navLinkStyle(false)}>
                <i className="fa-solid fa-user-plus"/>Get Started
              </Link>
            </>
          ) : onAdmin ? (
            <Link to="/dashboard" onClick={()=>setMenuOpen(false)} style={navLinkStyle(false)}>
              <i className="fa-solid fa-arrow-left"/>Back to Dashboard
            </Link>
          ) : (
            <>
              <div style={{ padding:'0.5rem 0.75rem', fontSize:'0.8rem', color:'#9ca3af', borderBottom:'1px solid #f3f4f6', marginBottom:4 }}>
                Signed in as <strong>{user.name}</strong>
              </div>
              <Link to="/dashboard" onClick={()=>setMenuOpen(false)} style={navLinkStyle(isActive('/dashboard'))}>
                <i className="fa-solid fa-gauge"/>Dashboard
              </Link>
              {user.role === 'ADMIN' && (
                <Link to="/admin" onClick={()=>setMenuOpen(false)} style={navLinkStyle(isActive('/admin'))}>
                  <i className="fa-solid fa-gear"/>Admin Panel
                </Link>
              )}
            </>
          )}
          {user && (
            <button onClick={handleLogout} style={{ ...navLinkStyle(false), border:'none', background:'none', cursor:'pointer', color:'#dc2626', marginTop:4, borderTop:'1px solid #f3f4f6', paddingTop:10, textAlign:'left' }}>
              <i className="fa-solid fa-right-from-bracket"/>Logout
            </button>
          )}
        </div>
      )}

      <style>{`
        @media (max-width: 640px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: flex !important; }
        }
        .hide-xs { }
        @media (max-width: 480px) { .hide-xs { display: none; } }
      `}</style>
    </>
  );
}
